import React from 'react';

const ArticleCard = ({ title, category, imageUrl, size = 'medium' }) => {
    const sizeClasses = {
        small: 'col-span-1 row-span-1',
        medium: 'col-span-1 row-span-2',
        large: 'col-span-2 row-span-2',
    };

    return (
        <div className={`group relative border-4 border-black bg-white transition-all duration-300 hover:-translate-y-2 hover:shadow-hard cursor-pointer overflow-hidden flex flex-col ${sizeClasses[size]}`}>
            <div className="relative w-full flex-grow overflow-hidden border-b-4 border-black">
                <img
                    src={imageUrl}
                    alt={title}
                    className="w-full h-full object-cover filter grayscale group-hover:grayscale-0 transition-all duration-500 transform group-hover:scale-105"
                />
                <div className="absolute top-4 left-4 bg-soft-blue-400 border-2 border-black px-3 py-1 font-bold text-xs uppercase tracking-wider shadow-hard-sm">
                    {category}
                </div>
            </div>
            <div className="p-4 bg-white">
                <h3 className="font-serif font-bold text-xl leading-tight group-hover:text-soft-blue-700 transition-colors">
                    {title}
                </h3>
            </div>
        </div>
    );
};

export default ArticleCard;
